<?php
if (session_status() === PHP_SESSION_NONE) session_start();
if (empty($_SESSION['is_logged_in'])) { header('Location: ../connexion.php'); exit; }
if (!in_array($_SESSION['user_type'] ?? '', ['admin', 'gestionnaire', 'cuisinier'], true)) { header('Location: dashboard.php'); exit; }
require_once __DIR__ . '/../config/database.php';

function sh($value): string { return htmlspecialchars((string) $value, ENT_QUOTES, 'UTF-8'); }

$products = fetchAll("SELECT m.id,m.nom,m.stock_quantity,m.is_available,c.nom category_name,
    MAX(sm.created_at) last_movement
    FROM menus m LEFT JOIN categories c ON c.id=m.category_id AND c.supprimer=0
    LEFT JOIN stock_movements sm ON sm.menu_id=m.id AND sm.supprimer=0
    WHERE m.supprimer=0 GROUP BY m.id,m.nom,m.stock_quantity,m.is_available,c.nom ORDER BY m.stock_quantity ASC,m.nom");
$movements = fetchAll("SELECT sm.id,sm.type,sm.quantity,sm.raison,sm.created_at,m.nom menu_name
    FROM stock_movements sm JOIN menus m ON m.id=sm.menu_id
    WHERE sm.supprimer=0 ORDER BY sm.created_at DESC,sm.id DESC LIMIT 50");

$totalUnits = $outOfStock = $lowStock = 0;
foreach ($products as $product) {
    $stock = (int) $product->stock_quantity;
    $totalUnits += $stock;
    if ($stock <= 0) $outOfStock++;
    elseif ($stock <= 5) $lowStock++;
}
$name = trim(($_SESSION['user_nom'] ?? 'Utilisateur').' '.($_SESSION['user_prenom'] ?? ''));
$initials = strtoupper(substr($_SESSION['user_nom'] ?? 'U', 0, 1).substr($_SESSION['user_prenom'] ?? '', 0, 1));
$typeLabels = ['entree'=>'Entrée','sortie'=>'Sortie','ajustement'=>'Ajustement','perdus'=>'Perte'];
?>
<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Stocks — ISSALE</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Outfit:wght@600;700&display=swap" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css" rel="stylesheet">
<style>
:root{--p:#8B1A1A;--pd:#5C0E0E;--gold:#D4A373;--bg:#FDF8F3;--side:#1A120E;--text:#1A120E;--muted:#83766f;--border:#eadfd5;--green:#2d7d46;--red:#c0392b;--orange:#a76112;--font:'Inter',sans-serif;--display:'Outfit',sans-serif}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:var(--font)}.sidebar{position:fixed;inset:0 auto 0 0;width:256px;padding:24px;background:var(--side);display:flex;flex-direction:column;z-index:20}.brand{display:flex;gap:12px;align-items:center;margin-bottom:30px;color:#fff}.logo{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,var(--p),var(--pd));display:grid;place-items:center}.brand h1{font:700 18px var(--display);margin:0}.brand small{color:var(--gold)}nav{display:grid;gap:4px}.label{color:#887d78;font-size:10px;font-weight:700;letter-spacing:.12em;margin:12px 12px 5px}.nav{display:flex;align-items:center;gap:12px;padding:10px 13px;color:#bdb5b1;text-decoration:none;border-radius:11px;font-size:14px}.nav:hover{color:#fff;background:#ffffff12}.nav.active{background:var(--gold);color:#1A120E;font-weight:700}.user{margin-top:auto;padding-top:16px;border-top:1px solid #ffffff14;display:flex;gap:10px;align-items:center;color:#fff}.avatar{width:38px;height:38px;border-radius:11px;background:#ffffff12;color:var(--gold);display:grid;place-items:center;font-weight:700}.user p{margin:0;font-size:13px;font-weight:600}.user span{font-size:11px;color:#918783}.logout{margin-left:auto;color:#aaa}.main{margin-left:256px}.top{position:sticky;top:0;z-index:10;padding:17px 30px;background:#fdf8f3e8;backdrop-filter:blur(12px);border-bottom:1px solid var(--border)}.top>div{display:flex;gap:12px}.top h2{font:700 23px var(--display);margin:0}.top small{color:var(--muted)}.menu-btn{display:none;border:0;background:none;font-size:24px}.content{padding:30px}.crumb{font-size:13px;color:var(--muted);margin-bottom:20px}.crumb a{color:var(--p);text-decoration:none}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:22px}.stat{background:#fff;border:1px solid var(--border);border-radius:15px;padding:18px}.stat span{font-size:10px;text-transform:uppercase;color:var(--muted);font-weight:700}.stat strong{display:block;font:700 25px var(--display);margin-top:7px}.stat.alert strong{color:var(--orange)}.stat.danger strong{color:var(--red)}.toolbar{display:flex;justify-content:space-between;gap:12px;margin-bottom:18px}.search{position:relative;max-width:360px;flex:1}.search i{position:absolute;left:14px;top:13px;color:#999}.search input,.filter{padding:12px 14px;border:1px solid var(--border);border-radius:11px;background:#fff;font:14px var(--font)}.search input{width:100%;padding-left:40px}.tools{display:flex;gap:8px}.btn{border:0;border-radius:10px;padding:11px 14px;font:600 12px var(--font);cursor:pointer;display:inline-flex;align-items:center;gap:7px}.primary{background:var(--p);color:#fff}.light{background:#f4ede7}.card{background:#fff;border:1px solid var(--border);border-radius:18px;overflow:hidden;margin-bottom:24px}.card-title{padding:17px 18px;border-bottom:1px solid var(--border);font:700 16px var(--display)}.wrap{overflow:auto}table{width:100%;border-collapse:collapse}th{background:#fbf6f1;padding:13px 16px;text-align:left;text-transform:uppercase;font-size:10px;color:#94867e}td{padding:14px 16px;border-top:1px solid var(--border);font-size:12px;color:var(--muted)}tr:hover td{background:#fdf9f5}.product{font-weight:700;color:var(--text)}.stock{font:700 18px var(--display);color:var(--text)}.badge{display:inline-block;padding:5px 9px;border-radius:99px;font-size:10px;font-weight:700}.ok,.entree{background:#e8f5ec;color:var(--green)}.low,.ajustement{background:#fff0df;color:var(--orange)}.empty,.sortie,.perdus{background:#fce8e8;color:var(--red)}.overlay{position:fixed;inset:0;background:#1a120e88;display:none;align-items:center;justify-content:center;padding:20px;z-index:100}.overlay.open{display:flex}.modal{width:min(520px,100%);background:#fff;border-radius:20px}.head{display:flex;justify-content:space-between;padding:20px 23px;border-bottom:1px solid var(--border)}.head h3{font:700 19px var(--display);margin:0}.close{border:0;background:none;font-size:23px;cursor:pointer}.body{padding:22px}.foot{display:flex;justify-content:flex-end;gap:8px;padding:17px 22px;border-top:1px solid var(--border)}.field{margin-bottom:14px}.field label{display:block;font-size:12px;font-weight:700;margin-bottom:6px}.field input,.field select{width:100%;padding:11px;border:1px solid var(--border);border-radius:10px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.full{grid-column:1/-1}.toast{position:fixed;right:22px;bottom:22px;background:#1A120E;color:#fff;padding:14px 18px;border-radius:11px;z-index:200}.mobile-overlay{display:none}@media(max-width:900px){.stats{grid-template-columns:repeat(2,1fr)}}@media(max-width:768px){.sidebar{transform:translateX(-100%);transition:.2s}.sidebar.open{transform:none}.mobile-overlay.open{display:block;position:fixed;inset:0;background:#0006;z-index:15}.main{margin:0}.menu-btn{display:block}.content{padding:18px 14px}.toolbar{flex-direction:column}.tools{flex-wrap:wrap}.grid{grid-template-columns:1fr}.full{grid-column:auto}}@media(max-width:480px){.stats{grid-template-columns:1fr}}
</style></head><body>
<aside class="sidebar" id="sidebar"><div class="brand"><div class="logo"><i class="bi bi-cup-hot-fill"></i></div><div><h1>ISSALE</h1><small>Administration</small></div></div><nav><div class="label">Menu</div><a class="nav" href="dashboard.php"><i class="bi bi-grid-1x2"></i>Tableau de bord</a><a class="nav active" href="stocks.php"><i class="bi bi-box-seam"></i>Stocks</a></nav><div class="user"><div class="avatar"><?=sh($initials)?></div><div><p><?=sh($name)?></p><span><?=sh(ucfirst($_SESSION['user_type']??''))?></span></div><a class="logout" href="../models/logout.php" title="Déconnexion"><i class="bi bi-box-arrow-right"></i></a></div></aside><div class="mobile-overlay" id="mobileOverlay" onclick="toggleSidebar()"></div>
<main class="main"><header class="top"><div><button class="menu-btn" onclick="toggleSidebar()"><i class="bi bi-list"></i></button><div><h2>Gestion des stocks</h2><small>Niveaux disponibles et derniers mouvements</small></div></div></header><section class="content"><div class="crumb"><a href="dashboard.php">Tableau de bord</a> / Stocks</div>
<div class="stats"><div class="stat"><span>Produits suivis</span><strong><?=count($products)?></strong></div><div class="stat"><span>Unités disponibles</span><strong><?=$totalUnits?></strong></div><div class="stat alert"><span>Stock faible (1 à 5)</span><strong><?=$lowStock?></strong></div><div class="stat danger"><span>Ruptures</span><strong><?=$outOfStock?></strong></div></div>
<div class="toolbar"><div class="search"><i class="bi bi-search"></i><input id="search" oninput="filterStocks()" placeholder="Rechercher un produit…"></div><div class="tools"><select class="filter" id="levelFilter" onchange="filterStocks()"><option value="">Tous les niveaux</option><option value="ok">Disponible</option><option value="low">Stock faible</option><option value="empty">Rupture</option></select><button class="btn primary" onclick="stockModal.classList.add('open')"><i class="bi bi-plus-lg"></i>Nouveau mouvement</button></div></div>
<div class="card"><div class="card-title">État actuel</div><div class="wrap"><table><thead><tr><th>Produit</th><th>Catégorie</th><th>Quantité</th><th>Niveau</th><th>Disponibilité menu</th><th>Dernier mouvement</th></tr></thead><tbody id="stockRows"><?php if(!$products):?><tr><td colspan="6" style="text-align:center;padding:45px">Aucun produit enregistré.</td></tr><?php endif;?><?php foreach($products as $p):$qty=(int)$p->stock_quantity;$level=$qty<=0?'empty':($qty<=5?'low':'ok');$label=$level==='empty'?'Rupture':($level==='low'?'Stock faible':'Disponible');?><tr data-level="<?=$level?>" data-search="<?=sh(strtolower($p->nom.' '.($p->category_name??'')))?>"><td class="product"><?=sh($p->nom)?></td><td><?=sh($p->category_name?:'—')?></td><td><span class="stock"><?=$qty?></span></td><td><span class="badge <?=$level?>"><?=$label?></span></td><td><?=((int)$p->is_available)?'Visible':'Masqué'?></td><td><?= $p->last_movement ? date('d/m/Y H:i',strtotime($p->last_movement)) : '—' ?></td></tr><?php endforeach;?></tbody></table></div></div>
<div class="card"><div class="card-title">50 derniers mouvements</div><div class="wrap"><table><thead><tr><th>Date</th><th>Produit</th><th>Type</th><th>Quantité</th><th>Raison</th></tr></thead><tbody><?php if(!$movements):?><tr><td colspan="5" style="text-align:center;padding:40px">Aucun mouvement enregistré.</td></tr><?php endif;?><?php foreach($movements as $m):?><tr><td><?=date('d/m/Y H:i',strtotime($m->created_at))?></td><td class="product"><?=sh($m->menu_name)?></td><td><span class="badge <?=sh($m->type)?>"><?=sh($typeLabels[$m->type]??$m->type)?></span></td><td><?=in_array($m->type,['entree','ajustement'],true)?'+':'−'?><?=abs((int)$m->quantity)?></td><td><?=sh($m->raison?:'—')?></td></tr><?php endforeach;?></tbody></table></div></div></section></main>
<div class="overlay" id="stockModal"><form class="modal" onsubmit="saveStock(event)"><div class="head"><h3>Nouveau mouvement</h3><button type="button" class="close" onclick="stockModal.classList.remove('open')">×</button></div><div class="body"><div class="grid"><div class="field full"><label>Produit</label><select name="menu_id" required><?php foreach($products as $p):?><option value="<?=$p->id?>"><?=sh($p->nom)?> — stock <?=$p->stock_quantity?></option><?php endforeach;?></select></div><div class="field"><label>Type</label><select name="type"><option value="entree">Entrée</option><option value="sortie">Sortie</option><option value="ajustement">Ajustement positif</option><option value="perdus">Perte</option></select></div><div class="field"><label>Quantité</label><input type="number" min="1" name="quantity" required></div><div class="field full"><label>Raison</label><input name="raison" required placeholder="Achat, inventaire, perte…"></div></div></div><div class="foot"><button type="button" class="btn light" onclick="stockModal.classList.remove('open')">Annuler</button><button class="btn primary">Valider</button></div></form></div>
<script>
function toggleSidebar(){sidebar.classList.toggle('open');mobileOverlay.classList.toggle('open')}
function filterStocks(){const q=search.value.toLowerCase(),level=levelFilter.value;document.querySelectorAll('#stockRows tr[data-search]').forEach(row=>row.style.display=(!q||row.dataset.search.includes(q))&&(!level||row.dataset.level===level)?'':'none')}
async function saveStock(e){e.preventDefault();const button=e.submitter;button.disabled=true;const data=Object.fromEntries(new FormData(e.target));data.action='adjust_stock';try{const response=await fetch('../models/traitement/commandes-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});const out=await response.json();toast(out.message);if(out.success)setTimeout(()=>location.reload(),700)}catch(error){toast('Une erreur est survenue.')}finally{button.disabled=false}}
function toast(message){document.querySelector('.toast')?.remove();const item=document.createElement('div');item.className='toast';item.textContent=message;document.body.append(item);setTimeout(()=>item.remove(),3500)}
stockModal.onclick=e=>{if(e.target===stockModal)stockModal.classList.remove('open')};
</script><script src="../assets/js/sidebar-sync.js?v=3"></script></body></html>
